namespace DocSummary.Models;

public class SummarizeRequest
{
    public required string DocumentText { get; set; }

    /// <summary>
    /// Maximum number of sentences in the summary. Defaults to 3.
    /// </summary>
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
    public int OriginalLength { get; set; }
    public int SummaryLength { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public class DocumentSummarizationService
{
    /// <summary>
    /// Produces an extractive summary by scoring sentences on word frequency
    /// and returning the top-ranked ones in their original order.
    /// </summary>
    public string Summarize(string text, int maxSentences)
    {
        if (string.IsNullOrWhiteSpace(text))
            return string.Empty;

        var sentences = SplitSentences(text);
        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = BuildWordFrequencies(text);
        var scored = sentences
            .Select((sentence, index) => (Index: index, Score: ScoreSentence(sentence, wordFrequencies)))
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .OrderBy(s => s.Index) // preserve original order
            .Select(s => sentences[s.Index]);

        return string.Join(" ", scored);
    }

    private static List<string> SplitSentences(string text)
    {
        return Regex.Split(text, @"(?<=[.!?])\s+")
            .Where(s => !string.IsNullOrWhiteSpace(s))
            .Select(s => s.Trim())
            .ToList();
    }

    private static Dictionary<string, int> BuildWordFrequencies(string text)
    {
        var words = Regex.Matches(text.ToLowerInvariant(), @"\b[a-z]{2,}\b")
            .Select(m => m.Value);

        var stopWords = new HashSet<string>
        {
            "the", "is", "at", "which", "on", "and", "or", "an", "as", "be",
            "was", "were", "been", "are", "have", "has", "had", "do", "does",
            "did", "but", "if", "not", "no", "can", "could", "will", "would",
            "shall", "should", "may", "might", "it", "its", "of", "in", "to",
            "for", "with", "by", "from", "that", "this", "these", "those", "a"
        };

        var freq = new Dictionary<string, int>();
        foreach (var word in words)
        {
            if (stopWords.Contains(word)) continue;
            freq[word] = freq.GetValueOrDefault(word) + 1;
        }
        return freq;
    }

    private static double ScoreSentence(string sentence, Dictionary<string, int> wordFrequencies)
    {
        var words = Regex.Matches(sentence.ToLowerInvariant(), @"\b[a-z]{2,}\b")
            .Select(m => m.Value);

        return words.Sum(w => wordFrequencies.GetValueOrDefault(w));
    }
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly DocumentSummarizationService _service;

    public SummarizeController(DocumentSummarizationService service)
    {
        _service = service;
    }

    [HttpPost]
    public IActionResult Summarize([FromBody] SummarizeRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.DocumentText))
            return BadRequest(new { error = "DocumentText is required." });

        if (request.MaxSentences < 1)
            return BadRequest(new { error = "MaxSentences must be at least 1." });

        var summary = _service.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.DocumentText.Length,
            SummaryLength = summary.Length
        });
    }
}

